class UnionFind:
    def __init__(self, n: int):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, x: int) -> int:
        while self.parent[x] != x:
            self.parent[x] = self.parent[self.parent[x]]  # path compression
            x = self.parent[x]
        return x

    def union(self, x: int, y: int) -> None:
        rx, ry = self.find(x), self.find(y)
        if rx == ry:
            return
        if self.rank[rx] < self.rank[ry]:
            rx, ry = ry, rx
        self.parent[ry] = rx
        if self.rank[rx] == self.rank[ry]:
            self.rank[rx] += 1


def deduplicate(docs: list[str], duplicate_pairs: list[tuple[int, int]]) -> list[str]:
    uf = UnionFind(len(docs))
    for i, j in duplicate_pairs:
        uf.union(i, j)
    # Keep the document with the lowest index in each group
    keep = {uf.find(i) for i in range(len(docs))}
    return [docs[i] for i in sorted(keep)]


deduped = deduplicate(docs, duplicate_pairs)
print(f"{len(docs)} -> {len(deduped)} documents after semantic dedup")
